bool isEven(int n)
{
    return n % 2 == 0;
}

// used exactly once, somewhere far below, just to filter a list

#include <iostream>

using namespace std;

int main()
{
    auto isEven = [](int n) { return n % 2 == 0; };

    cout << isEven(4) << endl;
    cout << isEven(7) << endl;

    return 0;
}

int threshold = 10;

auto isAboveThreshold = [threshold](int n) { return n > threshold; }; // captures threshold BY VALUE (a copy)

auto isAboveThresholdRef = [&threshold](int n) { return n > threshold; }; // captures threshold BY REFERENCE

